module RefModule(
    input [3:0] a,
    input [3:0] b,
    input sub,
    output [3:0] sum
);wire [3:0] neg_b;
      wire _n01 = ~b[0] ^ 1[0];
  wire _c01 = ~b[0] & 1[0];
  wire _n02 = ~b[1] ^ 1[1] ^ _c01;
  wire _c02 = (~b[1] & 1[1]) | (~b[1] & _c01) | (1[1] & _c01);
  wire _n03 = ~b[2] ^ 1[2] ^ _c02;
  wire _c03 = (~b[2] & 1[2]) | (~b[2] & _c02) | (1[2] & _c02);
  wire _n04 = ~b[3] ^ 1[3] ^ _c03;
